import React, { useState, useEffect } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { useAuth } from '../context/AuthContext';
import toast from 'react-hot-toast';
import Navbar from '../components/Navbar';
import LoadingSpinner from '../components/LoadingSpinner';

const PropertyDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useAuth();
  const [property, setProperty] = useState(null);
  const [loading, setLoading] = useState(true);
  const [inquiryMessage, setInquiryMessage] = useState('');
  const [showInquiryForm, setShowInquiryForm] = useState(false);
  const [isFavorite, setIsFavorite] = useState(false);
  const [sendingInquiry, setSendingInquiry] = useState(false);

  useEffect(() => {
    fetchProperty();
    if (user) {
      checkFavorite();
    }
  }, [id, user]);

  const fetchProperty = async () => {
    try {
      const response = await axios.get(`/properties/${id}`);
      setProperty(response.data);
    } catch (error) {
      console.error('Error fetching property:', error);
      toast.error('Property not found');
      navigate('/properties');
    } finally {
      setLoading(false);
    }
  };

  const checkFavorite = async () => {
    try {
      const response = await axios.get('/users/favorites');
      const favorites = response.data;
      setIsFavorite(favorites.some(fav => fav.property._id === id));
    } catch (error) {
      console.error('Error checking favorites:', error);
    }
  };

  const handleInquiry = async (e) => {
    e.preventDefault();
    if (!user) {
      toast.error('Please login to send an inquiry');
      navigate('/login');
      return;
    }

    setSendingInquiry(true);
    try {
      await axios.post('/inquiries', {
        propertyId: id,
        message: inquiryMessage
      });
      toast.success('Inquiry sent successfully!');
      setInquiryMessage('');
      setShowInquiryForm(false);
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to send inquiry');
    } finally {
      setSendingInquiry(false);
    }
  };

  const toggleFavorite = async () => {
    if (!user) {
      toast.error('Please login to save favorites');
      navigate('/login');
      return;
    }

    try {
      if (isFavorite) {
        await axios.delete(`/users/favorites/${id}`);
        setIsFavorite(false);
        toast.success('Removed from favorites');
      } else {
        await axios.post('/users/favorites', { propertyId: id });
        setIsFavorite(true);
        toast.success('Added to favorites');
      }
    } catch (error) {
      toast.error(error.response?.data?.message || 'Failed to update favorites');
    }
  };

  const formatPrice = (price) => {
    return new Intl.NumberFormat('en-US', {
      style: 'currency',
      currency: 'USD',
      maximumFractionDigits: 0
    }).format(price);
  };

  if (loading) return <LoadingSpinner />;
  if (!property) return null;

  return (
    <div>
      <Navbar />
      <div className="container mx-auto px-4 py-8">
        <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
          <div className="lg:col-span-2">
            <div className="bg-white rounded-lg shadow-lg overflow-hidden">
              <div className="relative h-96">
                {property.images && property.images.length > 0 ? (
                  <img
                    src={property.images[0]}
                    alt={property.title}
                    className="w-full h-full object-cover"
                  />
                ) : (
                  <div className="w-full h-full bg-gradient-to-br from-blue-100 to-purple-100 flex items-center justify-center">
                    <span className="text-gray-400 text-lg">No image available</span>
                  </div>
                )}
                <div className="absolute top-4 right-4 space-x-2">
                  <span className={`px-3 py-1 rounded-full text-sm font-semibold ${
                    property.listingType === 'sale'
                      ? 'bg-green-500 text-white'
                      : 'bg-blue-500 text-white'
                  }`}>
                    {property.listingType === 'sale' ? 'FOR SALE' : 'FOR RENT'}
                  </span>
                  {property.status !== 'approved' && (
                    <span className="px-3 py-1 rounded-full text-sm font-semibold bg-yellow-500 text-white">
                      {property.status.toUpperCase()}
                    </span>
                  )}
                </div>
              </div>
              <div className="p-6">
                <div className="flex justify-between items-start mb-4">
                  <h1 className="text-3xl font-bold text-gray-900">{property.title}</h1>
                  <button
                    onClick={toggleFavorite}
                    className={`px-4 py-2 rounded-lg transition ${
                      isFavorite
                        ? 'bg-red-500 text-white hover:bg-red-600'
                        : 'bg-gray-200 text-gray-700 hover:bg-gray-300'
                    }`}
                  >
                    {isFavorite ? '★ Saved' : '☆ Save'}
                  </button>
                </div>
                <p className="text-gray-600 mb-4 flex items-center">
                  <svg className="w-5 h-5 mr-1" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M17.657 16.657L13.414 20.9a1.998 1.998 0 01-2.827 0l-4.244-4.243a8 8 0 1111.314 0z" />
                    <path strokeLinecap="round" strokeLinejoin="round" strokeWidth={2} d="M15 11a3 3 0 11-6 0 3 3 0 016 0z" />
                  </svg>
                  {property.location}
                </p>
                <p className="text-3xl font-bold text-blue-600 mb-6">
                  {formatPrice(property.price)}
                  {property.listingType === 'rent' && <span className="text-lg font-normal">/month</span>}
                </p>

                <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-6">
                  <div className="text-center p-3 bg-gray-50 rounded-lg">
                    <div className="font-semibold text-lg">{property.bedrooms}</div>
                    <div className="text-sm text-gray-600">Bedrooms</div>
                  </div>
                  <div className="text-center p-3 bg-gray-50 rounded-lg">
                    <div className="font-semibold text-lg">{property.bathrooms}</div>
                    <div className="text-sm text-gray-600">Bathrooms</div>
                  </div>
                  <div className="text-center p-3 bg-gray-50 rounded-lg">
                    <div className="font-semibold text-lg">{property.area}</div>
                    <div className="text-sm text-gray-600">Sq Ft</div>
                  </div>
                  <div className="text-center p-3 bg-gray-50 rounded-lg">
                    <div className="font-semibold text-lg capitalize">{property.propertyType}</div>
                    <div className="text-sm text-gray-600">Property Type</div>
                  </div>
                </div>

                <div className="mb-6">
                  <h2 className="text-xl font-semibold mb-3">Description</h2>
                  <p className="text-gray-700 leading-relaxed">{property.description}</p>
                </div>

                <div>
                  <h2 className="text-xl font-semibold mb-3">Address</h2>
                  <p className="text-gray-700">{property.address}</p>
                </div>
              </div>
            </div>
          </div>

          <div className="lg:col-span-1">
            <div className="bg-white rounded-lg shadow-lg p-6 mb-6 sticky top-24">
              <h2 className="text-xl font-semibold mb-4">Contact Owner</h2>
              <div className="mb-4 p-4 bg-gray-50 rounded-lg">
                <p className="font-semibold text-gray-800">{property.owner.name}</p>
                <p className="text-gray-600 text-sm mt-1">Email: {property.owner.email}</p>
                {property.owner.phone && (
                  <p className="text-gray-600 text-sm mt-1">Phone: {property.owner.phone}</p>
                )}
              </div>

              {!showInquiryForm ? (
                <button
                  onClick={() => setShowInquiryForm(true)}
                  className="w-full btn-primary"
                >
                  Send Inquiry
                </button>
              ) : (
                <form onSubmit={handleInquiry}>
                  <textarea
                    value={inquiryMessage}
                    onChange={(e) => setInquiryMessage(e.target.value)}
                    placeholder="Write your message here... I'm interested in this property and would like to know more details."
                    className="w-full p-3 border rounded-lg mb-3 focus:outline-none focus:ring-2 focus:ring-blue-500"
                    rows="5"
                    required
                  />
                  <div className="flex space-x-2">
                    <button
                      type="submit"
                      disabled={sendingInquiry}
                      className="flex-1 btn-primary disabled:opacity-50"
                    >
                      {sendingInquiry ? 'Sending...' : 'Send'}
                    </button>
                    <button
                      type="button"
                      onClick={() => setShowInquiryForm(false)}
                      className="flex-1 bg-gray-300 text-gray-700 px-4 py-2 rounded-lg hover:bg-gray-400 transition"
                    >
                      Cancel
                    </button>
                  </div>
                </form>
              )}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default PropertyDetails;
